package store

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

// ValkeyStore implements the Store interface using Valkey
type ValkeyStore struct {
	client valkey.Client
}

// newValkeyStore creates a new Valkey store
func newValkeyStore() (*ValkeyStore, error) {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		return nil, fmt.Errorf("VALKEY_ADDR environment variable is required")
	}

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("VALKEY_PASSWORD_REQUIRED"); val != "" {
		passwordRequired = strings.ToLower(val) != "false"
	}

	if password == "" && passwordRequired {
		return nil, fmt.Errorf("VALKEY_PASSWORD is required (set VALKEY_PASSWORD_REQUIRED=false to disable)")
	}

	// Parse comma-separated addresses
	addresses := strings.Split(addr, ",")
	for i := range addresses {
		addresses[i] = strings.TrimSpace(addresses[i])
	}

	disableCache := false
	if val := os.Getenv("VALKEY_DISABLE_CACHE"); val != "" {
		disableCache = strings.ToLower(val) == "true"
	}

	forceSingle := false
	if val := os.Getenv("VALKEY_FORCE_SINGLE"); val != "" {
		forceSingle = strings.ToLower(val) == "true"
	}

	client, err := valkey.NewClient(valkey.ClientOption{
		InitAddress:       addresses,
		Password:          password,
		DisableCache:      disableCache,
		ForceSingleClient: forceSingle,
	})
	if err != nil {
		return nil, err
	}

	return &ValkeyStore{client: client}, nil
}

// Ping checks if Valkey is reachable
func (s *ValkeyStore) Ping(ctx context.Context) error {
	resp := s.client.B().Ping().Build()
	result, err := s.client.Do(ctx, resp).ToString()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

// GetSandboxBySessionID retrieves a sandbox by session ID
func (s *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := KeyPrefix + sessionID
	resp := s.client.B().Get().Key(key).Build()
	data, err := s.client.Do(ctx, resp).AsBytes()
	if err != nil {
		if valkey.IsValkeyNil(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}
	return &sandbox, nil
}

// StoreSandbox stores a new sandbox atomically
func (s *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return fmt.Errorf("expiresAt cannot be zero")
	}

	key := KeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	ttl := time.Until(sandbox.ExpiresAt) + time.Hour

	// Use MULTI/EXEC for atomicity
	pipe := s.client.B().Multi()

	// SETNX
	setnxResp := pipe.Sets().Set().Key(key).Value(string(data)).Nx().Ex(ttl).Build()

	// ZADD expiry
	expiryResp := pipe.Sets().Zadd().Key(ExpiryIndex).ScoreMember().ScoreMember(float64(sandbox.ExpiresAt.Unix()), sandbox.SessionID).Build()

	// ZADD activity
	activityResp := pipe.Sets().Zadd().Key(LastActivityIndex).ScoreMember().ScoreMember(float64(time.Now().Unix()), sandbox.SessionID).Build()

	execResp := pipe.Exec()

	results, err := s.client.DoMulti(ctx, setnxResp, expiryResp, activityResp, execResp)
	if err != nil {
		return err
	}

	// Check SETNX result
	setnxResult, err := results[0].AsInt64()
	if err != nil {
		return err
	}
	if setnxResult == 0 {
		return fmt.Errorf("session already exists")
	}

	return nil
}

// UpdateSandbox updates an existing sandbox
func (s *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}

	key := KeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	// Use SET with XX (only if exists)
	resp := s.client.B().Set().Key(key).Value(string(data)).Xx().Build()
	result, err := s.client.Do(ctx, resp).ToString()
	if err != nil {
		if valkey.IsValkeyNil(err) {
			return ErrNotFound
		}
		return err
	}
	if result != "OK" {
		return ErrNotFound
	}

	return nil
}

// DeleteSandboxBySessionID deletes a sandbox by session ID
func (s *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := KeyPrefix + sessionID

	pipe := s.client.B().Multi()
	delResp := pipe.Keys().Del().Key(key).Build()
	zremExpiryResp := pipe.Sets().Zrem().Key(ExpiryIndex).Member(sessionID).Build()
	zremActivityResp := pipe.Sets().Zrem().Key(LastActivityIndex).Member(sessionID).Build()
	execResp := pipe.Exec()

	_, err := s.client.DoMulti(ctx, delResp, zremExpiryResp, zremActivityResp, execResp)
	return err
}

// ListExpiredSandboxes lists sandboxes that expired before the given time
func (s *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	resp := s.client.B().Zrangebyscore().Key(ExpiryIndex).Query(valkey.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatInt(before.Unix(), 10),
		Count: int64(limit),
	}).Build()

	sessionIDs, err := s.client.Do(ctx, resp).AsStrSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

// ListInactiveSandboxes lists sandboxes that were inactive before the given time
func (s *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return []*types.SandboxInfo{}, nil
	}

	resp := s.client.B().Zrangebyscore().Key(LastActivityIndex).Query(valkey.ZRangeBy{
		Min:   "-inf",
		Max:   strconv.FormatInt(before.Unix(), 10),
		Count: int64(limit),
	}).Build()

	sessionIDs, err := s.client.Do(ctx, resp).AsStrSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

// loadSandboxesBySessionIDs loads sandboxes by their session IDs
func (s *ValkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = KeyPrefix + id
	}

	resp := s.client.B().Mget().Key(keys...).Build()
	values, err := s.client.Do(ctx, resp).AsStrSlice()
	if err != nil {
		return nil, err
	}

	var sandboxes []*types.SandboxInfo
	for i, val := range values {
		if val == "" {
			// Skip missing keys (orphan ZSET members)
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(val), &sandbox); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

// UpdateSessionLastActivity updates the last activity time for a session
func (s *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("sessionID cannot be empty")
	}

	// Verify session exists
	key := KeyPrefix + sessionID
	existsResp := s.client.B().Exists().Key(key).Build()
	exists, err := s.client.Do(ctx, existsResp).AsInt64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	zaddResp := s.client.B().Sets().Zadd().Key(LastActivityIndex).ScoreMember().ScoreMember(float64(at.Unix()), sessionID).Build()
	_, err = s.client.Do(ctx, zaddResp).AsInt64()
	return err
}

// Close closes the Valkey connection
func (s *ValkeyStore) Close() {
	s.client.Close()
}

