// newValkeyStore creates a new Valkey store
func newValkeyStore() (*ValkeyStore, error) {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		return nil, fmt.Errorf("VALKEY_ADDR environment variable is required")
	}

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := true
	if val := os.Getenv("VALKEY_PASSWORD_REQUIRED"); val != "" {
		passwordRequired = strings.ToLower(val) != "false"
	}

	if password == "" && passwordRequired {
		return nil, fmt.Errorf("VALKEY_PASSWORD is required (set VALKEY_PASSWORD_REQUIRED=false to disable)")
	}

	// Parse comma-separated addresses
	addresses := strings.Split(addr, ",")
	for i := range addresses {
		addresses[i] = strings.TrimSpace(addresses[i])
	}

	disableCache := false
	if val := os.Getenv("VALKEY_DISABLE_CACHE"); val != "" {
		disableCache = strings.ToLower(val) == "true"
	}

	forceSingle := false
	if val := os.Getenv("VALKEY_FORCE_SINGLE"); val != "" {
		forceSingle = strings.ToLower(val) == "true"
	}

	client, err := valkey.NewClient(valkey.ClientOption{
		InitAddress:       addresses,
		Password:          password,
		DisableCache:      disableCache,
		ForceSingleClient: forceSingle,
	})
	if err != nil {
		return nil, err
	}

	return &ValkeyStore{client: client}, nil
}

// Ping checks if Valkey is reachable
func (s *ValkeyStore) Ping(ctx context.Context) error {
	resp := s.client.B().Ping().Build()
	result, err := s.client.Do(ctx, resp).ToString()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

// GetSandboxBySessionID retrieves a sandbox by session ID
