package store

import (
	"context"
	"errors"
	"testing"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

func TestErrNotFound(t *testing.T) {
	if ErrNotFound == nil {
		t.Error("ErrNotFound should not be nil")
	}
	if !errors.Is(ErrNotFound, ErrNotFound) {
		t.Error("ErrNotFound should match itself")
	}
}

func TestKeyConstants(t *testing.T) {
	if KeyPrefix == "" {
		t.Error("KeyPrefix should not be empty")
	}
	if ExpiryIndex == "" {
		t.Error("ExpiryIndex should not be empty")
	}
	if LastActivityIndex == "" {
		t.Error("LastActivityIndex should not be empty")
	}
}

func TestSandboxInfoValidate(t *testing.T) {
	tests := []struct {
		name    string
		info    *types.SandboxInfo
		wantErr bool
	}{
		{
			name: "valid sandbox",
			info: &types.SandboxInfo{
				SessionID: "test-session",
				SandboxID: "test-sandbox",
				Name:      "test-name",
				Namespace: "test-namespace",
				Kind:      types.SandboxKind,
				ExpiresAt: time.Now().Add(time.Hour),
			},
			wantErr: false,
		},
		{
			name: "missing session id",
			info: &types.SandboxInfo{
				SandboxID: "test-sandbox",
				Name:      "test-name",
				Namespace: "test-namespace",
				Kind:      types.SandboxKind,
				ExpiresAt: time.Now().Add(time.Hour),
			},
			wantErr: true,
		},
		{
			name: "missing sandbox id",
			info: &types.SandboxInfo{
				SessionID: "test-session",
				Name:      "test-name",
				Namespace: "test-namespace",
				Kind:      types.SandboxKind,
				ExpiresAt: time.Now().Add(time.Hour),
			},
			wantErr: true,
		},
		{
			name: "missing name",
			info: &types.SandboxInfo{
				SessionID: "test-session",
				SandboxID: "test-sandbox",
				Namespace: "test-namespace",
				Kind:      types.SandboxKind,
				ExpiresAt: time.Now().Add(time.Hour),
			},
			wantErr: true,
		},
		{
			name: "missing namespace",
			info: &types.SandboxInfo{
				SessionID: "test-session",
				SandboxID: "test-sandbox",
				Name:      "test-name",
				Kind:      types.SandboxKind,
				ExpiresAt: time.Now().Add(time.Hour),
			},
			wantErr: true,
		},
		{
			name: "missing kind",
			info: &types.SandboxInfo{
				SessionID: "test-session",
				SandboxID: "test-sandbox",
				Name:      "test-name",
				Namespace: "test-namespace",
				ExpiresAt: time.Now().Add(time.Hour),
			},
			wantErr: true,
		},
		{
			name: "zero expires at",
			info: &types.SandboxInfo{
				SessionID: "test-session",
				SandboxID: "test-sandbox",
				Name:      "test-name",
				Namespace: "test-namespace",
				Kind:      types.SandboxKind,
			},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.info.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("SandboxInfo.Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestCreateSandboxRequestValidate(t *testing.T) {
	tests := []struct {
		name    string
		req     *types.CreateSandboxRequest
		wantErr bool
	}{
		{
			name: "valid agent runtime request",
			req: &types.CreateSandboxRequest{
				Kind:      types.AgentRuntimeKind,
				Name:      "test-runtime",
				Namespace: "default",
			},
			wantErr: false,
		},
		{
			name: "valid code interpreter request",
			req: &types.CreateSandboxRequest{
				Kind:      types.CodeInterpreterKind,
				Name:      "test-interpreter",
				Namespace: "default",
			},
			wantErr: false,
		},
		{
			name: "invalid kind",
			req: &types.CreateSandboxRequest{
				Kind:      "InvalidKind",
				Name:      "test",
				Namespace: "default",
			},
			wantErr: true,
		},
		{
			name: "missing namespace",
			req: &types.CreateSandboxRequest{
				Kind: types.AgentRuntimeKind,
				Name: "test",
			},
			wantErr: true,
		},
		{
			name: "missing name",
			req: &types.CreateSandboxRequest{
				Kind:      types.AgentRuntimeKind,
				Namespace: "default",
			},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.req.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("CreateSandboxRequest.Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestCreateSandboxResponseValidate(t *testing.T) {
	tests := []struct {
		name    string
		resp    *types.CreateSandboxResponse
		wantErr bool
	}{
		{
			name: "valid response",
			resp: &types.CreateSandboxResponse{
