			},
			wantErr: true,
		},
		{
			name: "missing sandbox id",
			resp: &types.CreateSandboxResponse{
				SessionID:   "test-session",
				SandboxName: "test-name",
			},
			wantErr: true,
		},
		{
			name: "missing sandbox name",
			resp: &types.CreateSandboxResponse{
				SessionID: "test-session",
				SandboxID: "test-sandbox",
			},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.resp.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("CreateSandboxResponse.Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestSandboxInfoJSON(t *testing.T) {
	now := time.Now()
	sandbox := &types.SandboxInfo{
		SessionID:    "test-session",
		SandboxID:    "test-sandbox",
		Name:         "test-name",
		Namespace:    "test-namespace",
		Kind:         types.SandboxKind,
		PodIP:        "10.0.0.1",
		ExpiresAt:    now.Add(time.Hour),
		CreatedAt:    now,
		LastActivity: now,
		EntryPoints: []types.EntryPoint{
			{
				Path:     "/api",
				Protocol: "HTTP",
				Endpoint: "localhost:8080",
			},
		},
	}

	data, err := sandbox.MarshalJSON()
	if err != nil {
		t.Fatalf("MarshalJSON failed: %v", err)
	}

	var unmarshaled types.SandboxInfo
	if err := unmarshaled.UnmarshalJSON(data); err != nil {
		t.Fatalf("UnmarshalJSON failed: %v", err)
	}

	if unmarshaled.SessionID != sandbox.SessionID {
		t.Errorf("SessionID mismatch: got %s, want %s", unmarshaled.SessionID, sandbox.SessionID)
	}
	if unmarshaled.SandboxID != sandbox.SandboxID {
		t.Errorf("SandboxID mismatch: got %s, want %s", unmarshaled.SandboxID, sandbox.SandboxID)
	}
	if unmarshaled.Name != sandbox.Name {
		t.Errorf("Name mismatch: got %s, want %s", unmarshaled.Name, sandbox.Name)
	}
}

func TestEntryPoint(t *testing.T) {
	ep := types.EntryPoint{
		Path:     "/api/v1",
		Protocol: "HTTPS",
		Endpoint: "example.com:443",
	}

	if ep.Path != "/api/v1" {
		t.Errorf("Path mismatch: got %s", ep.Path)
	}
	if ep.Protocol != "HTTPS" {
		t.Errorf("Protocol mismatch: got %s", ep.Protocol)
	}
	if ep.Endpoint != "example.com:443" {
		t.Errorf("Endpoint mismatch: got %s", ep.Endpoint)
	}
}

func TestStoreInterface(t *testing.T) {
	var s Store
	_ = s
}

func TestContextCancellation(t *testing.T) {
	ctx, cancel := context.WithCancel(context.Background())
	cancel()

	if ctx.Err() == nil {
		t.Error("Context should be cancelled")
	}
}

