package workloadmanager

import (
	"testing"
	"time"
)

func TestDefaultSandboxTTL(t *testing.T) {
	if DefaultSandboxTTL != 8*time.Hour {
		t.Errorf("DefaultSandboxTTL = %v, want 8h", DefaultSandboxTTL)
	}
}

func TestDefaultSandboxIdleTimeout(t *testing.T) {
	if DefaultSandboxIdleTimeout != 15*time.Minute {
		t.Errorf("DefaultSandboxIdleTimeout = %v, want 15m", DefaultSandboxIdleTimeout)
	}
}

func TestDefaultSessionTimeout(t *testing.T) {
	if DefaultSessionTimeout != 15*time.Minute {
		t.Errorf("DefaultSessionTimeout = %v, want 15m", DefaultSessionTimeout)
	}
}

func TestTokenCacheCapacity(t *testing.T) {
	if TokenCacheCapacity != 1000 {
		t.Errorf("TokenCacheCapacity = %d, want 1000", TokenCacheCapacity)
	}
}

func TestTokenCacheTTL(t *testing.T) {
	if TokenCacheTTL != 5*time.Minute {
		t.Errorf("TokenCacheTTL = %v, want 5m", TokenCacheTTL)
	}
}

func TestSandboxCreationTimeout(t *testing.T) {
	if SandboxCreationTimeout != 2*time.Minute {
		t.Errorf("SandboxCreationTimeout = %v, want 2m", SandboxCreationTimeout)
	}
}

func TestSandboxDeleteTimeout(t *testing.T) {
	if SandboxDeleteTimeout != 30*time.Second {
		t.Errorf("SandboxDeleteTimeout = %v, want 30s", SandboxDeleteTimeout)
	}
}

func TestGCTickInterval(t *testing.T) {
	if GCTickInterval != 15*time.Second {
		t.Errorf("GCTickInterval = %v, want 15s", GCTickInterval)
	}
}

func TestHTTPReadTimeout(t *testing.T) {
	if HTTPReadTimeout != 15*time.Second {
		t.Errorf("HTTPReadTimeout = %v, want 15s", HTTPReadTimeout)
	}
}

func TestHTTPIdleTimeout(t *testing.T) {
	if HTTPIdleTimeout != 90*time.Second {
		t.Errorf("HTTPIdleTimeout = %v, want 90s", HTTPIdleTimeout)
	}
}

func TestHTTPShutdownTimeout(t *testing.T) {
	if HTTPShutdownTimeout != 15*time.Second {
		t.Errorf("HTTPShutdownTimeout = %v, want 15s", HTTPShutdownTimeout)
	}
}

func TestLabelAndAnnotationKeys(t *testing.T) {
	tests := []struct {
		name     string
		constant string
	}{
		{"LastActivityAnnotationKey", LastActivityAnnotationKey},
		{"SandboxNameLabelKey", SandboxNameLabelKey},
		{"SessionIDLabelKey", SessionIDLabelKey},
		{"PodNameAnnotationKey", PodNameAnnotationKey},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if tt.constant == "" {
				t.Errorf("Constant %s should not be empty", tt.name)
			}
		})
	}
}

func TestNewConfig(t *testing.T) {
	cfg := NewConfig()
	if cfg == nil {
		t.Fatal("NewConfig() returned nil")
	}

	if cfg.Port != 8080 {
		t.Errorf("Port = %d, want 8080", cfg.Port)
	}
	if cfg.EnableTLS != false {
		t.Error("EnableTLS should be false by default")
	}
	if cfg.EnableAuth != false {
		t.Error("EnableAuth should be false by default")
	}
	if cfg.InCluster != true {
		t.Error("InCluster should be true by default")
	}
	if cfg.ReadTimeout != HTTPReadTimeout {
		t.Errorf("ReadTimeout = %v, want %v", cfg.ReadTimeout, HTTPReadTimeout)
	}
	if cfg.IdleTimeout != HTTPIdleTimeout {
		t.Errorf("IdleTimeout = %v, want %v", cfg.IdleTimeout, HTTPIdleTimeout)
	}
	if cfg.SandboxTTL != DefaultSandboxTTL {
		t.Errorf("SandboxTTL = %v, want %v", cfg.SandboxTTL, DefaultSandboxTTL)
	}
	if cfg.IdleTimeoutDuration != DefaultSandboxIdleTimeout {
		t.Errorf("IdleTimeoutDuration = %v, want %v", cfg.IdleTimeoutDuration, DefaultSandboxIdleTimeout)
	}
}

func TestConfigValidate(t *testing.T) {
	tests := []struct {
		name    string
		config  *Config
		wantErr bool
	}{
		{
			name: "valid config",
			config: &Config{
				Port: 8080,
			},
			wantErr: false,
		},
		{
			name: "port too low",
			config: &Config{
				Port: 0,
			},
			wantErr: true,
		},
		{
			name: "port too high",
			config: &Config{
				Port: 70000,
			},
			wantErr: true,
		},
		{
			name: "tls enabled without cert path",
			config: &Config{
				Port:      8080,
				EnableTLS: true,
			},
			wantErr: true,
		},
		{
			name: "tls enabled without key path",
			config: &Config{
				Port:        8080,
				EnableTLS:   true,
				TLSCertPath: "/path/to/cert",
			},
			wantErr: true,
		},
		{
			name: "tls enabled with both paths",
			config: &Config{
				Port:        8080,
				EnableTLS:   true,
				TLSCertPath: "/path/to/cert",
				TLSKeyPath:  "/path/to/key",
			},
			wantErr: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.config.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("Config.Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

